import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"Phase 01 Scope and Non-Goals","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/product/preview-scope.md","filePath":"sovereign-os/product/preview-scope.md"}'),r={name:"sovereign-os/product/preview-scope.md"};function n(l,e,s,d,c,p){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="phase-01-scope-and-non-goals" tabindex="-1">Phase 01 Scope and Non-Goals <a class="header-anchor" href="#phase-01-scope-and-non-goals" aria-label="Permalink to &quot;Phase 01 Scope and Non-Goals&quot;">​</a></h1><p><strong>Status:</strong> Draft<br><strong>Version:</strong> 0.2<br><strong>Detailed plan:</strong> <a href="./../roadmap/01-preview-poc.html">Flashable Pi-hole Image POC</a></p><h2 id="scope-statement" tabindex="-1">Scope Statement <a class="header-anchor" href="#scope-statement" aria-label="Permalink to &quot;Scope Statement&quot;">​</a></h2><p>Phase 01 proves that Sovereign can deliver a useful home appliance as one flashable Raspberry Pi image. A user writes the image, boots a Raspberry Pi 5, and receives an operational Pi-hole service at:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://sovereign.local/dns/admin/</span></span></code></pre></div><p>The post-POC Console Foundation adds a read-only platform entry point at <code>http://sovereign.local/</code>, which redirects to <code>/console/</code>. Pi-hole remains an independent service under <code>/dns/*</code>.</p><p>The phase validates distribution and appliance foundations, not the AI-native platform.</p><h2 id="included" tabindex="-1">Included <a class="header-anchor" href="#included" aria-label="Permalink to &quot;Included&quot;">​</a></h2><ul><li>Raspberry Pi 5 with 16 GB RAM as the sole target.</li><li>Raspberry Pi OS Lite 64-bit base.</li><li>One reproducible compressed disk image.</li><li>Docker Engine and Compose deployment boundary.</li><li>Official Pi-hole ARM64 container pinned by immutable digest.</li><li>Pi-hole artifact embedded for offline first boot.</li><li>Persistent Pi-hole configuration and data.</li><li>Unique device identity and Pi-hole credential generated on first boot.</li><li>Nginx routing Pi-hole under <code>/dns/*</code>.</li><li>Avahi/mDNS providing <code>sovereign.local</code>.</li><li>Direct-IP fallback.</li><li>Automatic startup and idempotent first-boot initialization.</li><li>DNS, HTTP, reboot, interruption, persistence, resource, and release tests.</li><li>Checksums, release metadata, flashing instructions, router DNS instructions, and known limitations.</li></ul><h2 id="explicit-non-goals" tabindex="-1">Explicit Non-Goals <a class="header-anchor" href="#explicit-non-goals" aria-label="Permalink to &quot;Explicit Non-Goals&quot;">​</a></h2><ul><li>General-purpose administration dashboard or mutating management API. The bounded, read-only Console health surface is tracked separately in the <a href="./../roadmap/01-console-foundation.html">Console Foundation plan</a>.</li><li>Local or remote LLM, AI chat, capability registry, or Pi-hole AI adapter.</li><li>Voice or wake-word support.</li><li>Home Assistant, documents, calendar, or other service integrations.</li><li>A general plugin lifecycle or marketplace.</li><li>Public internet exposure or remote administration.</li><li>Automatic router configuration.</li><li>Pi-hole DHCP enabled by default.</li><li>Multi-user support.</li><li>Broad hardware, OS, SD/USB/NVMe, or architecture support without testing.</li><li>Production-grade automatic update, rollback, or support guarantees.</li><li>Replacing Raspberry Pi OS or creating a new Linux distribution from scratch.</li></ul><h2 id="required-external-user-action" tabindex="-1">Required External User Action <a class="header-anchor" href="#required-external-user-action" aria-label="Permalink to &quot;Required External User Action&quot;">​</a></h2><p>Pi-hole will be operational immediately after first boot, but network-wide filtering requires the user to configure a router or individual devices to use the Raspberry Pi&#39;s stable IP address as DNS. The image must not attempt to modify unknown router settings or enable a competing DHCP server automatically.</p><h2 id="change-control" tabindex="-1">Change Control <a class="header-anchor" href="#change-control" aria-label="Permalink to &quot;Change Control&quot;">​</a></h2><p>An item may enter Phase 01 only when it is required to produce, boot, access, secure, diagnose, or verify the Pi-hole appliance image. All AI and broader platform work remains in the master-plan backlog until this phase meets its exit criteria.</p>',15)])])}const m=a(r,[["render",n]]);export{h as __pageData,m as default};
